changeSet.sql:
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'java_user') THEN
CREATE ROLE java_user WITH LOGIN PASSWORD 'java_password';
GRANT CONNECT ON DATABASE weather_db TO java_user;
        GRANT USAGE ON SCHEMA public TO java_user;
        GRANT ALL PRIVILEGES ON ALL TABLES IN SCHEMA public TO java_user;
        GRANT ALL PRIVILEGES ON ALL SEQUENCES IN SCHEMA public TO java_user;
END IF;
END
$$;

GRANT ALL ON SCHEMA public TO java_user;
GRANT CREATE ON SCHEMA public TO java_user;
ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT ALL ON TABLES TO java_user;
ALTER DEFAULT PRIVILEGES IN SCHEMA public GRANT ALL ON SEQUENCES TO java_user;
